import redis

r = redis.Redis(host='localhost', port=6379, decode_responses=True)

# Producer: fire-and-forget
def enqueue_email(payload: dict):
    r.lpush('jobs:email', json.dumps(payload))

# Consumer: blocking pop with safe processing list
def consume():
    while True:
        raw = r.brpoplpush('jobs:email', 'jobs:email:processing', timeout=0)
        try:
            job = json.loads(raw)
            send_email(job)
            r.lrem('jobs:email:processing', 1, raw)
        except Exception:
            r.lrem('jobs:email:processing', 1, raw)
            r.lpush('jobs:email:dead', raw)

import { Queue, Worker, FlowProducer } from 'bullmq';
import { Redis } from 'ioredis';

const connection = new Redis({ maxRetriesPerRequest: null });
const queue = new Queue('tasks', { connection });

// Priority job — processed before priority:5 jobs
await queue.add('critical-alert', { userId: 42 }, { priority: 1 });

// Repeatable job — cron stored in bull:tasks:repeat ZSET
await queue.add('daily-digest', {}, { repeat: { cron: '0 9 * * *' } });

// Rate-limited worker — token bucket enforced in Redis
const worker = new Worker('tasks', async job => { await process(job); }, {
  connection,
  limiter: { max: 50, duration: 10_000 },
});

// Dependency flow — parent waits in bull:tasks:waiting-children
const flow = new FlowProducer({ connection });
await flow.add({
  name: 'send-report',
  queueName: 'tasks',
  children: [
    { name: 'fetch-data', queueName: 'tasks', data: { source: 'db' } },
    { name: 'render-pdf', queueName: 'tasks', data: { template: 'v2' } },
  ],
});

import { createClient } from 'redis';

const client = createClient();
await client.connect();

// Producer: append to stream
await client.xAdd('events:orders', '*', {
  orderId: 'ord_123',
  status: 'placed',
  ts: Date.now().toString(),
});

// Consumer group read with acknowledgment
const messages = await client.xReadGroup(
  'processing-group',
  'worker-1',
  [{ key: 'events:orders', id: '>' }],
  { COUNT: 10, BLOCK: 2000 }
);

for (const { id } of messages?.[0]?.messages ?? []) {
  // process...
  await client.xAck('events:orders', 'processing-group', id);
}

import fakeredis
import pytest

@pytest.fixture
def redis_client():
    return fakeredis.FakeRedis(decode_responses=True)

def consume_once(r, stream, group, consumer):
    msgs = r.xreadgroup(group, consumer, {stream: ">"}, count=1, block=0)
    for _, entries in msgs:
        for msg_id, data in entries:
            process(data)          # your handler
            r.xack(stream, group, msg_id)

def test_ack_clears_pel(redis_client):
    r = redis_client
    r.xgroup_create("jobs", "workers", id="$", mkstream=True)
    r.xadd("jobs", {"task": "embed"})
    consume_once(r, "jobs", "workers", "c1")
    assert r.xpending("jobs", "workers")["pending"] == 0
